={
    "where": {
        "key": {
            "remoteJid": "{{
  (() => {
    const tel = String($json.body?.telefone || '').trim();
    if (!tel) return null;

    // já tem @lid
    if (tel.includes('@lid')) return tel;

    // já tem @s.whatsapp.net
    if (tel.includes('@s.whatsapp.net')) return tel;

    // adiciona sufixo padrão
    return `${tel}@s.whatsapp.net`;
  })()
}}"
        }
    },
    "page": 1,
    "offset": 300
}

